const tx = $input.first().json.data || $input.first().json;
const triggerData = $('New Transaction').item.json;
const fileName = triggerData.name || 'unknown';
const fileId   = triggerData.id   || '';

const fileNumMatch = fileName.match(/^([A-Z0-9-]+)/i);
const fileNumber = tx.fileNumber || (fileNumMatch ? fileNumMatch[1] : 'Unknown');

// Property address from flat fields
const propertyAddress = [tx.propertyStreet, tx.propertyCity, tx.propertyState, tx.propertyZip]
  .filter(Boolean).join(', ') || 'N/A';

const purchasePrice = parseFloat(tx.purchasePrice) || 0;
const paymentMethod = tx.paymentMethod || 'Unknown';
const financingType = tx.financingType || 'Unknown';
const buyerType     = tx.buyerType     || 'Individual';
const buyerName     = tx.buyerLegalName|| 'Unknown';
const sellerName    = tx.sellerLegalName|| 'Unknown';

// Entity check
const entityTypes = ['llc','corporation','corp','inc','trust','partnership','lp','llp'];
const isEntity = entityTypes.some(t => buyerType.toLowerCase().includes(t));

// Non-financed check
// Non-financed = explicitly cash/none, AND not a known financed type
const financedTypes = ['conventional','fha','va','usda','financed','mortgage','loan'];
const isFinancedByLender = financedTypes.some(t => (financingType||'').toLowerCase().includes(t));
const isNonFinanced = !isFinancedByLender && ['none','cash','all-cash','non-financed'].some(t =>
  (financingType || '').toLowerCase().includes(t) ||
  (paymentMethod  || '').toLowerCase() === 'cash' ||
  (paymentMethod  || '').toLowerCase() === 'wire'
);

const isResidential = (tx.propertyType || '').toLowerCase().includes('residential');

// FinCEN reporting determination
let isReportable  = false;
const reportReason = [];

if (isNonFinanced && isResidential) {
  if (isEntity) {
    isReportable = true;
    reportReason.push('Entity buyer in non-financed residential transaction');
  }
  if (purchasePrice >= 300000) {
    isReportable = true;
    reportReason.push(`Amount $${purchasePrice.toLocaleString()} meets threshold`);
  }
  if ((paymentMethod||'').toLowerCase().includes('cash') && purchasePrice >= 100000) {
    isReportable = true;
    reportReason.push('Cash payment method');
  }
}

// Data gaps
const dataGaps = [];
if (isEntity && (tx.beneficialOwnersCount || 0) === 0)
  dataGaps.push('Missing beneficial owner info for entity buyer');
if (!tx.buyerTinLast4 || tx.buyerTinLast4 === 'N/A')
  dataGaps.push('Missing buyer TIN/SSN');

const reportStatus = isReportable
  ? (dataGaps.length > 0 ? 'Reportable - Data Needed' : 'Ready to Report')
  : 'Not Reportable';

return [{ json: {
  fileNumber,
  transactionType:       tx.transactionType        || 'Unknown',
  closingDate:           tx.closingDate             || 'N/A',
  propertyType:          tx.propertyType            || 'N/A',
  propertyAddress,
  propertyCounty:        tx.propertyCounty          || 'N/A',
  propertyState:         tx.propertyState           || 'N/A',
  purchasePrice,
  paymentMethod,
  financingType,
  isNonFinanced,
  buyerType,
  isEntityBuyer:         isEntity,
  buyerName,
  buyerAddress:          tx.buyerAddress            || 'N/A',
  buyerTIN:              tx.buyerTinLast4            || 'N/A',
  buyerFormationState:   tx.buyerFormationState     || 'N/A',
  beneficialOwnerCount:  tx.beneficialOwnersCount   || 0,
  beneficialOwnerSummary:tx.beneficialOwnersSummary || 'None',
  sellerType:            tx.sellerType              || 'N/A',
  sellerName,
  sellerAddress:         tx.sellerAddress           || 'N/A',
  titleCompany:          tx.titleCompany            || 'N/A',
  closingAgent:          tx.closingAgent            || 'N/A',
  additionalParties:     tx.additionalParties       || 'None',
  isReportable,
  reportReason:          reportReason.join('; ')    || 'Does not meet reporting criteria',
  reportStatus,
  dataGaps:              dataGaps.join('; ')        || 'None',
  fileName,
  fileId,
  processedAt: new Date().toISOString()
}}];

